script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  if (f._action == 'Edit') {f._siteOutIdentity = f.getItemValue('ma_kho');}
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&VoucherLogHandleStatus; if (f._action == 'Edit') {f._siteOutIdentity = f.getItemValue('ma_kho');}}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d65')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d65')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt:t_tien');
    v.addGridFields(g, 'gia_nt,tien_nt:gia,tien');
    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'], ['t_tien', 'tien']]);
    v.set_referenceFields(null);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d65'&ListTabChange;&PostTabChange;]]);
      &PostCurrencySelected;
    }
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d65'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}



function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'SourceSite':
      if (result[0].Value) {
        f.setItemValue('vi_tri_yn', result[0].Value);
        break;
      }
      f.setItemValue('vi_tri_yn', result[0][1]);
      var g = f.getItem("d65")._controlBehavior;
      insertGrid(g, result);
      break;
    case 'DestinationSite':
      f.setItemValue('vi_trin_yn', result[0].Value);
      break;
    case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
       break;
  }
}
/* <flatten type="Javascript"> */
function onChange$Voucher$SourceSite(o) {
  var g = o.parentForm.getItem("d65")._controlBehavior;
  set$Voucher$Site$EmptyLocation(g, 'ma_vi_tri');
  var $k = [], i = g._getColumnOrder('ma_vt'), l = g._getColumnOrder('ma_lo');
  for (var r = 1; r <= g._rowCount; r++) {
    var a = $func.trim(g._getItemValue(r, l)), b = $func.trim(g._getItemValue(r, i));
    if (validate$GridVoucherDetail$Object(g, r, 'ma_vt') && ($func.trim(a) == '' || (validate$GridVoucherDetail$Object(g, r, 'ma_lo')))) {
      var v = b + String.fromCharCode(255) + a
      if !($k.indexOf(v) != -1) Array.add($k, v);
    }
  }
  o.parentForm.request('SourceSite', 'SourceSite', ['ma_kho', 'ma_dvcs', ['voucherCode', 'String', o.parentForm._voucherCode], ['k', 'Infinite', $k], ['action', 'Decimal', o.parentForm._action == 'Edit' ? 1 : 0]], o);
}
function onChange$Voucher$DestinationSite(o) {
  o.parentForm.request('DestinationSite', 'DestinationSite', ['ma_khon', 'ma_dvcs'], o);
  var g = o.parentForm.getItem("d65")._controlBehavior;
  set$Voucher$Site$EmptyLocation(g, 'ma_vi_trin');
}
function onChange$Voucher$Date(o) {o.parentForm.getItem('ngay_ct').value = o.parentForm.getItem('ngay_lct').value;}
function onChange$Voucher$Step(o) {o.parentForm.setReferenceKeyFilter('ma_khon');}
function set$Voucher$Site$EmptyLocation(g, c) {
  var o = g._activeCell, l = g._getColumnOrder(c);
  if (l == g._activeColumn) {
    if (o._controlBehavior) {
      var fields = g._fields, field = g._fields[l - 1], r = o.row, id = g.get_id();
      if (field.ItemKeyFilter) o._controlBehavior.set_completionKeyFilter($func.completionFilter(o, fields, field.ItemKeyFilter, r, id));
      if (field.ItemCheckFilter) o._controlBehavior.set_completionCheckFilter($func.completionFilter(o, fields, field.ItemCheckFilter, r, id));
    }
  }
  for (var i = 0; i < g._rowCount; i++) {
    o = g._getItem(i + 1, l);
    if (!o.row) o.value = '';
      else {
        o.row = i + 1;
        g.setItemGridBehavior(o, [[c, '', '']]);
      }
  }
}
function when$VoucherCopying(f) {f.setItemValue('stt_rec', '');}

function insertGrid(g, a) {
  var l0 = g._getColumnOrder('ma_vt'), l1 = g._getColumnOrder('ma_lo'), l2 = g._getColumnOrder('ton13');
  for (var r = 1; r <= g._rowCount; r++) {
    var v1 = $func.trim(g._getItemValue(r, l0)), v2 = $func.trim(g._getItemValue(r, l1));
    for (var i = 0; i < a.length; i++){
      if ($func.trim(a[i][2]) == v1 && $func.trim(a[i][3]) == v2) {
        g._setItemValue(r, l2, a[i][4]);
      }
    }
  }
}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
/* </flatten> */
      &ListScript;
      &PostScript;
